import types, sys

class FakeXgr:
    class contrib:
        class hf:
            class LogitsProcessor:
                def __init__(self, cg):
                    self.cg = cg
                def __call__(self, input_ids, logits):
                    return logits

sys.modules['xgrammar'] = FakeXgr()

from outlines.backends.xgrammar import XGrammarLogitsProcessor

class FakeTensorAdapter:
    def shape(self, t):
        return t['shape']

p = XGrammarLogitsProcessor('grammar', max_batch_size=2)
p.tensor_adapter = FakeTensorAdapter()
logits = {'shape': (2, 10)}
input_ids = {'shape': (2, 5)}
p.process_logits(input_ids, logits)
print('ok batch=2')

p2 = XGrammarLogitsProcessor('grammar', max_batch_size=2)
p2.tensor_adapter = FakeTensorAdapter()
logits3 = {'shape': (3, 10)}
input_ids3 = {'shape': (3, 5)}
try:
    p2.process_logits(input_ids3, logits3)
    print('FAIL: no error raised')
except ValueError as e:
    print('raised:', e)

p3 = XGrammarLogitsProcessor('grammar', max_batch_size=0)
p3.tensor_adapter = FakeTensorAdapter()
logits1 = {'shape': (1, 10)}
input_ids1 = {'shape': (1, 5)}
try:
    p3.process_logits(input_ids1, logits1)
    print('FAIL: no error for max_batch_size=0')
except ValueError as e:
    print('raised:', e)

p4 = XGrammarLogitsProcessor('grammar', track_memory_usage=True)
p4.tensor_adapter = FakeTensorAdapter()
for i in range(12):
    p4.process_logits(input_ids1, logits1)
stats = p4.get_memory_stats()
print('stats:', stats['total_calls'], stats['peak_memory_mb']>=0, len(stats['memory_history']))
p4.reset()
print('after reset total_calls:', p4.get_memory_stats()['total_calls'])
"

